<tr>
<td>Letter Grade</td>
<td>Numerical Grade Point</td>
</tr>
</thead>
<tbody>
<tr>
<td><b>AA</b></td>
<td>4.00</td>
</tr>
<tr>
<td><b>BA</b></td>
<td>3.50</td>
</tr>
<tr>
<td><b>BB</b></td>
<td>3.00</td>
</tr>
